getAecbRecordId: async (mawaniReferenceId) => {
        const redisKey = `aecbRecordCounter_${mawaniReferenceId}`;
        let recordId = await redisService.getObj(redisKey);
        if (recordId === null) {
          recordId = aecbRecordIdCounter;
          await redisService.setObj(redisKey, recordId, cacheTtl.AECB_RECORD_ID_EXPIRATION);
        } else {
          recordId = await redisService.incrObj(redisKey);
        }
        logger.info(`Record Id for ${mawaniReferenceId} is :: ${recordId}`);
        return recordId;
      },

