getFinanceCounterPartyDetails: async (trx, financeData) => {
    let counterPartyDetails;
    if(!financeData.counterpartyId || financeData.counterpartyId === -1){
      [counterPartyDetails] = await _getInternalCounterPartyDetails(trx, financeData.financeId, counterPartyOrgCategory.FINANCE_APPLICATION) ;
    }
    else if(financeData.configJson.COUNTER_PARTY_TYPE == 'TRADING_PARTNER') {
      [counterPartyDetails] = await _getTradingPartnersInformationById(trx, financeData.counterpartyId);
    }else if(financeData.configJson.COUNTER_PARTY_TYPE == 'COUNTER_PARTY') {
      [counterPartyDetails] = await _getInternalOrgDetails(trx, financeData.counterpartyId) ;
    }

    return counterPartyDetails;
  },

