validateIfInvoiceNumberExists: async (trx, invoiceNumber, updateRequestId = null) => {
    const query = trx('lendingcreditfacility.facility_fee_invoice_details')
      .where({ invoice_number: invoiceNumber });

    if (updateRequestId) {
      query.andWhereNot('id', updateRequestId);
    }

    const existingInvoices = await query;
    const isInsertAllowed = existingInvoices.length === 0 || existingInvoices.every(inv => inv.status === 'Invoice Rejected by Checker');

    return isInsertAllowed;
  },

validateInvoiceAmount: async (trx, invoiceAmount, arId) => {
    const arDetail = await trx('lendingcreditfacility.facility_fee_ar_details')
    .select('amount_billed', 'facility_fees', 'balance_facility_fees', 'balance_tax')
    .where('id', arId);
    const newAmountBilled = Number(arDetail.balance_facility_fees || 0) + Number(arDetail.balance_tax || 0) + Number(invoiceAmount);
    if (newAmountBilled > Number(arDetail.facility_fees)) {
      return false;
    }
    return true;
  },

