const createJoiObjectForCountries = (type) =>{
  return Joi.when(`supported_finance_types`, {
    is: Joi.array().items(Joi.string().valid(type)),
    then: Joi.array().items(Joi.string()).unique().required(),
    otherwise: Joi.array().items(Joi.string()).unique().optional(),
  });
}

const getCountryValidation = (supportedTypes) => {
  const validationObject = {};
  for (const [type, value] of Object.entries(supportedTypes)) {
    let form = PRODUCT_TO_SHORT_FORM[value];
    const shortForm = form.split('_')[1];
    if (Object.values(COUNTER_PARTY_INCORPORATION_COUNTRIES_REQUIRED).includes(type))
      validationObject[`counter_party_incorporation_countries_${shortForm}`] = createJoiObjectForCountries(type);
    if (Object.values(CLIENT_INCORPORATION_COUNTRIES_REQUIRED).includes(type))
      validationObject[`client_incorporation_countries_${shortForm}`] = createJoiObjectForCountries(type);
  };
  return validationObject;
};

const getRestrictDibsursalValidation = (supportedTypes) => {
  const validationObject = {};
  for (const [type, value] of Object.entries(supportedTypes)) {
    let form = PRODUCT_TO_SHORT_FORM[value];
    const shortForm = form.split('_')[1];
    if(Object.values(RESTRICT_DIBSURSAL_INFORMATION_REQUIRED).includes(type))
      validationObject[`restrict_disbursal_${shortForm}`] = Joi.boolean().required();
  };
  return validationObject;
};

